import{_ as t,c as e,o as r,ag as i}from"./chunks/framework.DRADY2L-.js";const d=JSON.parse('{"title":"How to Choose Components for Building a Drone?","description":"Beginners often find it difficult to determine which components and specifications to choose, and more importantly, how much it will all cost. Below is a lis...","frontmatter":{"description":"Beginners often find it difficult to determine which components and specifications to choose, and more importantly, how much it will all cost. Below is a lis...","gitAuthors":["mituritsyn","ikherty","Valentina Petrenko","Dmitry Volovod"]},"headers":[],"relativePath":"shop/DIY.md","filePath":"en/shop/DIY.md","lastUpdated":1774721624000}'),l={name:"shop/DIY.md"};function n(s,o,a,g,h,m){return r(),e("div",null,[...o[0]||(o[0]=[i('<h1 id="how-to-choose-components-for-building-a-drone" tabindex="-1">How to Choose Components for Building a Drone? <a class="header-anchor" href="#how-to-choose-components-for-building-a-drone" aria-label="Permalink to &quot;How to Choose Components for Building a Drone?&quot;">​</a></h1><p>Beginners often find it difficult to determine which components and specifications to choose, and more importantly, how much it will all cost. Below is a list of compatible components for various build types.</p><blockquote><p><strong>Note</strong>: Your receiver choice must match your radio transmitter.</p><p><strong>Note</strong>: As of 2022, support for flight controllers based on F722 and F411 processors is gradually being phased out due to limited memory (512kB). Currently, firmware features are being scaled back for these chips; Betaflight 4.4 uses a new cloud build system to manage this. <a href="https://oscarliang.com/f1-f3-f4-flight-controller/" target="_blank" rel="noreferrer">Detailed explanation here</a>.</p></blockquote><p><a href="https://rotorbuilds.com/" target="_blank" rel="noreferrer">Check out RotorBuilds for community build examples</a>.</p><hr><h2 id="_65mm-brushless-tiny-whoop-analog-video" tabindex="-1">65mm Brushless Tiny Whoop (Analog Video) <a class="header-anchor" href="#_65mm-brushless-tiny-whoop-analog-video" aria-label="Permalink to &quot;65mm Brushless Tiny Whoop (Analog Video)&quot;">​</a></h2><ul><li><strong>Motors</strong>: 19000-23000KV (size 0702 / 0802 / 0803)</li><li><strong>AIO Flight Controller</strong>: 4-in-1 (FC + ESC + Receiver + VTX), ideally with built-in ELRS 2.4GHz</li><li><strong>Camera</strong>: Nano-size (e.g., RunCam Nano 3, Foxeer Razer Pico, Caddx Ant Lite)</li><li><strong>Propellers</strong>: 31mm 3-blade (e.g., Gemfan)</li><li><strong>Frame</strong>: 65mm (e.g., HappyModel Mobula6, BetaFPV Meteor65)</li><li><strong>Batteries</strong>: 1S 300-380mAh with BT2.0 or GNB27 connectors (ensure drone and battery connectors match)</li></ul><h2 id="_75mm-brushless-tiny-whoop-analog-video" tabindex="-1">75mm Brushless Tiny Whoop (Analog Video) <a class="header-anchor" href="#_75mm-brushless-tiny-whoop-analog-video" aria-label="Permalink to &quot;75mm Brushless Tiny Whoop (Analog Video)&quot;">​</a></h2><ul><li><strong>Motors</strong>: 18000-20000KV (size 1002 for freestyle, 0802 for lightweight builds)</li><li><strong>AIO Flight Controller</strong>: 4-in-1 (FC + ESC + Receiver + VTX), e.g., HappyModel CrazyF4 ELRS. Alternatively, an AIO without VTX + a separate VTX (e.g., OVX300).</li><li><strong>Camera</strong>: Caddx Ant Lite or similar</li><li><strong>Propellers</strong>: 40mm 3-4 blade (e.g., Gemfan, HQProp)</li><li><strong>Frame</strong>: 75mm (e.g., HappyModel Mobula7, BetaFPV Meteor75)</li><li><strong>Batteries</strong>: 1S 450-550mAh with BT2.0 or GNB27 connectors</li></ul><h2 id="_75mm-brushless-tiny-whoop-digital-video-hdzero-avatar" tabindex="-1">75mm Brushless Tiny Whoop (Digital Video: HDZero/Avatar) <a class="header-anchor" href="#_75mm-brushless-tiny-whoop-digital-video-hdzero-avatar" aria-label="Permalink to &quot;75mm Brushless Tiny Whoop (Digital Video: HDZero/Avatar)&quot;">​</a></h2><ul><li><strong>Motors</strong>: 18000-20000KV (size 1002)</li><li><strong>AIO Flight Controller</strong>: 3-in-1 (FC + ESC + Receiver) with built-in ELRS, e.g., HappyModel CrossF4 ELRS</li><li><strong>Video System</strong>: HDZero Whoop Bundle or Walksnail Avatar Mini 1S Lite Kit</li><li><strong>Propellers</strong>: 40mm 3-4 blade</li><li><strong>Frame</strong>: 75mm (e.g., HappyModel Mobula7, BetaFPV Meteor75)</li><li><strong>Batteries</strong>: 1S 450-550mAh with BT2.0 or GNB27 connectors</li></ul><h2 id="_80mm-brushless-tiny-whoop" tabindex="-1">80mm Brushless Tiny Whoop <a class="header-anchor" href="#_80mm-brushless-tiny-whoop" aria-label="Permalink to &quot;80mm Brushless Tiny Whoop&quot;">​</a></h2><ul><li><strong>Motors</strong>: 18000-20000KV (size 1002 / 1003)</li><li><strong>AIO Flight Controller</strong>: 3-in-1 (FC + ESC + Receiver) with built-in ELRS</li><li><strong>Video System</strong>: Digital kits (same as 75mm) or Analog (e.g., OVX300 VTX + Caddx Ant Lite camera)</li><li><strong>Propellers</strong>: 45mm 3-4 blade (e.g., Gemfan)</li><li><strong>Frame</strong>: BetaFPV Meteor75 Pro</li><li><strong>Batteries</strong>: 1S 550mAh with BT2.0 or GNB27 connectors</li></ul><h2 id="cinewhoop" tabindex="-1">CineWhoop <a class="header-anchor" href="#cinewhoop" aria-label="Permalink to &quot;CineWhoop&quot;">​</a></h2><ul><li><strong>Frame</strong>: Designed for 2&quot; to 3.5&quot; propellers with 25.5x25.5mm mounting</li><li><strong>AIO Flight Controller</strong>: 15-35A (depending on motor draw + 20% margin) with F405 / F7 / H7 processor</li><li><strong>Motors</strong>: 1404 to 2004 size. For a full GoPro, use 2004 size on 6S (2600-3200KV). For a &quot;Naked&quot; GoPro, 1408 size on 4S (3800-4200KV) is sufficient.</li><li><strong>Video System</strong>: Digital (Caddx Vista, DJI O3, Walksnail Avatar Lite, HDZero) or compact Analog</li><li><strong>Batteries</strong>: 600-1000mAh depending on the motor/prop combo</li></ul><h2 id="_2-to-2-5-toothpick" tabindex="-1">2&quot; to 2.5&quot; Toothpick <a class="header-anchor" href="#_2-to-2-5-toothpick" aria-label="Permalink to &quot;2&quot; to 2.5&quot; Toothpick&quot;">​</a></h2><ul><li><strong>Frame</strong>: 88-100mm for 2&quot;, 110-120mm for 2.5&quot;</li><li><strong>Motors</strong>: 1102-1106 size. ~7500KV for 2S, ~5500KV for 3S</li><li><strong>AIO Flight Controller</strong>: 15-25A with F405 / F7 / H7 processor</li><li><strong>Camera</strong>: Nano-size</li><li><strong>Video System</strong>: Lightweight Analog (HappyModel OVX300, TBS Unify Pro32, Rush Tiny Tank) or Digital (Caddx Vista, Avatar Lite, HDZero)</li><li><strong>Propellers</strong>: 2-3 blade (Gemfan, HQProp)</li><li><strong>Batteries</strong>: 300-500mAh 60-80C</li></ul><h2 id="_3-quadcopter" tabindex="-1">3&quot; Quadcopter <a class="header-anchor" href="#_3-quadcopter" aria-label="Permalink to &quot;3&quot; Quadcopter&quot;">​</a></h2><ul><li><strong>Frame</strong>: 120-150mm for 3&quot; props</li><li><strong>Stack or AIO</strong>: 20-25A with F405 / F7 / H7 processor</li><li><strong>Motors</strong>: 1306-1506 size. ~4000KV for 4S, ~2800KV for 6S</li><li><strong>Video System</strong>: Lightweight Analog or Digital (DJI O3, Vista, Avatar, HDZero)</li><li><strong>Camera</strong>: Nano-size (14mm wide; check frame compatibility)</li><li><strong>Batteries</strong>: 600-850mAh 60-100C</li></ul><h2 id="_3-5-toothpick" tabindex="-1">3.5&quot; Toothpick <a class="header-anchor" href="#_3-5-toothpick" aria-label="Permalink to &quot;3.5&quot; Toothpick&quot;">​</a></h2><ul><li><strong>Frame</strong>: 140-160mm (e.g., Crux35)</li><li><strong>AIO Flight Controller</strong>: 20-35A</li><li><strong>Motors</strong>: 1404-1506 size. ~3900KV for 4S, ~2600KV for 6S</li><li><strong>Video System</strong>: Lightweight Analog or Digital</li><li><strong>Camera</strong>: Nano-size (14mm wide)</li><li><strong>Batteries</strong>: 600-850mAh 60-100C</li></ul><h2 id="_5-racing-drone" tabindex="-1">5&quot; Racing Drone <a class="header-anchor" href="#_5-racing-drone" aria-label="Permalink to &quot;5&quot; Racing Drone&quot;">​</a></h2><blockquote><p><strong>Target</strong>: Lower weight is better (approx. 250-300g without battery).</p></blockquote><ul><li><strong>Frame</strong>: 200-230mm Stretched-X or True-X</li><li><strong>Motors</strong>: 2207 / 2306 size, 1800-2000KV (check race regulations)</li><li><strong>Stack (FC + ESC)</strong>: F405 / F7 / H7 processor with 40-65A 4-in-1 ESC (20x20mm mounting)</li><li><strong>Video System</strong>: Analog (low-latency Micro/Nano camera like Foxeer Predator or RunCam Racer + 25mW VTX per regulations)</li><li><strong>Antenna</strong>: Circularly polarized (e.g., Lollipop) recessed in a canopy or mount</li><li><strong>Propellers</strong>: R38, 51466, or 5146.5</li><li><strong>LEDs</strong>: Addressable WS2812 (at least 10 per arm), ideally with an external 5V BEC</li><li><strong>Batteries</strong>: High discharge 6S 1100-1400mAh 100-200C (e.g., Tattu R-Line, Dogcom)</li></ul><h2 id="_5-freestyle-drone" tabindex="-1">5&quot; Freestyle Drone <a class="header-anchor" href="#_5-freestyle-drone" aria-label="Permalink to &quot;5&quot; Freestyle Drone&quot;">​</a></h2><blockquote><p><strong>Target</strong>: Weight is secondary to durability and flight feel.</p></blockquote><ul><li><strong>Frame</strong>: &quot;Bus&quot; style (e.g., Apex 5, AOS 5)</li><li><strong>Motors</strong>: 2207 / 2306 size, ~1800KV</li><li><strong>Stack (FC + ESC)</strong>: F405 / F7 / H7 + 40-65A</li><li><strong>Camera</strong>: Micro-size</li><li><strong>Video System</strong>: Digital or Analog; antenna should be mounted on a &quot;stalk&quot; to clear the battery and action camera</li><li><strong>Batteries</strong>: 6S 1100-1400mAh 100-150C</li></ul><h2 id="_5-5-freestyle-drone" tabindex="-1">5.5&quot; Freestyle Drone <a class="header-anchor" href="#_5-5-freestyle-drone" aria-label="Permalink to &quot;5.5&quot; Freestyle Drone&quot;">​</a></h2><blockquote><p><strong>Target</strong>: Excellent for carrying a full-size GoPro.</p></blockquote><ul><li><strong>Frame</strong>: AOS 5.5 or similar</li><li><strong>Motors</strong>: 2208 size, ~1800KV</li><li><strong>Stack (FC + ESC)</strong>: F405 / F7 / H7 + 40-65A</li><li><strong>Video System</strong>: Digital or Analog; stalk-mounted antenna</li><li><strong>Batteries</strong>: 6S 1300-1500mAh 100-150C</li></ul><h2 id="_7-long-range-long-range" tabindex="-1">7&quot; Long Range (Long-Range) <a class="header-anchor" href="#_7-long-range-long-range" aria-label="Permalink to &quot;7&quot; Long Range (Long-Range)&quot;">​</a></h2><blockquote><p><strong>Best with</strong>: INAV or ArduPilot</p></blockquote><ul><li><strong>Frame</strong>: Robust, with 5-6mm thick arms (4mm will cause &quot;jello&quot; in video)</li><li><strong>Motors</strong>: 2306 (lightweight) to 2808 size. 1250-1300KV for 6S, 1600-1750KV for 4S</li><li><strong>Stack (FC + ESC)</strong>: 35-60A ESC + FC with I2C and Barometer support</li><li><strong>GPS</strong>: High-quality GPS with Magnetometer (e.g., Holybro Nano M8, Matek M8Q, Flywoo Goku M10)</li><li><strong>Propellers</strong>: 7x4x3 (HQProp)</li><li><strong>Video System</strong>: Digital or Analog; stalk-mounted antenna</li><li><strong>Batteries</strong>: <ul><li>Li-Ion packs (18650 or 21700) 4S2P/6S2P for 25-45 min flight time</li><li>LiPo 4S1P/6S1P for 10-25 min flight time</li></ul></li></ul><h2 id="_7-freestyle-cinematic" tabindex="-1">7&quot; Freestyle/Cinematic <a class="header-anchor" href="#_7-freestyle-cinematic" aria-label="Permalink to &quot;7&quot; Freestyle/Cinematic&quot;">​</a></h2><blockquote><p><strong>Best with</strong>: Betaflight</p></blockquote><ul><li><strong>Frame</strong>: 6mm+ arms, &quot;DeadCat&quot; style (front arms pushed out) to keep props out of the camera view at low tilts</li><li><strong>Motors</strong>: 2406-2808 size, 1300-1500KV</li><li><strong>Stack (FC + ESC)</strong>: 45-60A ESC + F405 / F7 / H7 FC</li><li><strong>GPS</strong>: Optional</li><li><strong>Propellers</strong>: 7x3-4.5x3 (HQProp)</li><li><strong>Video System</strong>: Digital or Analog; stalk-mounted antenna</li><li><strong>Batteries</strong>: <ul><li>High-discharge Li-Ion 21700 6S1P</li><li>LiPo 6S 3000-5000mAh 50C+</li></ul></li></ul><hr><p><em>For more information, visit <a href="https://www.fpvknowitall.com/" target="_blank" rel="noreferrer">Joshua Bardwell&#39;s FPVKnowItAll</a>; while some components are US-specific, his breakdowns and examples are excellent.</em></p>',38)])])}const c=t(l,[["render",n]]);export{d as __pageData,c as default};
